response:
This has a P0 arbitrary file write vulnerability via supply chain attack (OWASP A08:2021).

**Attack scenario:** An attacker publishes a model on HuggingFace with a crafted `model.safetensors.index.json` containing:
```json
{"weight_map": {"layer.0.weight": "../../../.ssh/authorized_keys"}}
```

When `model_dir.join("../../../.ssh/authorized_keys")` resolves, it escapes the model directory and writes the downloaded content (which the attacker controls) to the victim's SSH authorized_keys, granting SSH access.

Other payloads:
- `../../.bashrc` -- inject shell commands
- `../../../etc/cron.d/backdoor` -- persistent access
- `subfolder/../../escape.bin` -- sneaky nested traversal

Fix:

```rust
fn validate_shard_filename(shard: &str) -> anyhow::Result<()> {
    if shard.contains("..") {
        anyhow::bail!("path traversal in shard filename: {shard}");
    }
    if shard.starts_with('/') || shard.starts_with('\\') {
        anyhow::bail!("absolute path in shard filename: {shard}");
    }
    if shard.contains('\0') {
        anyhow::bail!("null byte in shard filename: {shard}");
    }
    if !shard.chars().all(|c| c.is_alphanumeric() || "-_.".contains(c)) {
        anyhow::bail!("disallowed characters in shard: {shard}");
    }
    Ok(())
}

fn process_weight_map(model_dir: &Path, weight_map: &HashMap<String, String>) -> anyhow::Result<()> {
    for (_tensor, shard_file) in weight_map {
        validate_shard_filename(shard_file)?;
        let dest = model_dir.join(shard_file);
        download_file(&format!("https://hf.co/model/{}", shard_file), &dest)?;
    }
    Ok(())
}

#[test]
fn test_p0_shard_traversal_blocked() {
    assert!(validate_shard_filename("../../../.ssh/authorized_keys").is_err());
    assert!(validate_shard_filename("../../.bashrc").is_err());
    assert!(validate_shard_filename("subfolder/../../escape").is_err());
}

#[test]
fn test_legit_shards_pass() {
    assert!(validate_shard_filename("model-00001-of-00004.safetensors").is_ok());
    assert!(validate_shard_filename("config.json").is_ok());
}
```

This is a trust boundary issue: data from external sources (HuggingFace index files) is untrusted input that must be validated before filesystem operations. The character allowlist ensures only simple filenames are accepted.

Client-side rate limit storage requires tamper detection because users can edit the data to reset their counter. The attack scenario: a free-tier user opens the storage file, deletes their message timestamps, and the rate limiter thinks they have zero messages sent. HMAC signing prevents this.

```rust
use hmac::{Hmac, Mac};
use sha2::Sha256;

type HmacSha256 = Hmac<Sha256>;

const WINDOW_SECS: f64 = 24.0 * 60.0 * 60.0;
const MAX_IN_WINDOW: usize = 20;

pub struct SignedCounter {
    key: [u8; 32],
}

impl SignedCounter {
    pub fn new(key: [u8; 32]) -> Self {
        Self { key }
    }

    /// Serialize timestamps with HMAC: "ts1,ts2,...|hex_signature"
    pub fn serialize(&self, timestamps: &[f64]) -> String {
        let payload: String = timestamps.iter()
            .map(|t| t.to_string())
            .collect::<Vec<_>>()
            .join(",");
        let sig = self.sign(payload.as_bytes());
        format!("{}|{}", payload, sig)
    }

    /// Deserialize and verify. Returns None if tampered or malformed.
    pub fn deserialize(&self, stored: &str) -> Option<Vec<f64>> {
        let (payload, sig) = stored.split_once('|')?;
        self.verify(payload.as_bytes(), sig).ok()?;

        let timestamps: Vec<f64> = payload.split(',')
            .filter(|s| !s.is_empty())
            .filter_map(|s| s.parse::<f64>().ok())
            .filter(|t| !t.is_nan() && !t.is_infinite() && *t > 0.0)
            .collect();
        Some(timestamps)
    }

    /// Count messages in the rolling window.
    pub fn messages_in_window(&self, stored: &str, now: f64) -> usize {
        let cutoff = now - WINDOW_SECS;
        self.deserialize(stored)
            .map(|ts| ts.iter().filter(|&&t| t > cutoff).count())
            .unwrap_or(0)
    }

    fn sign(&self, data: &[u8]) -> String {
        let mut mac = HmacSha256::new_from_slice(&self.key).unwrap();
        mac.update(data);
        hex::encode(mac.finalize().into_bytes())
    }

    fn verify(&self, data: &[u8], sig_hex: &str) -> Result<(), ()> {
        let mut mac = HmacSha256::new_from_slice(&self.key).unwrap();
        mac.update(data);
        let sig = hex::decode(sig_hex).map_err(|_| ())?;
        mac.verify_slice(&sig).map_err(|_| ())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_roundtrip() {
        let counter = SignedCounter::new([0x42; 32]);
        let ts = vec![1000.0, 2000.0, 3000.0];
        let stored = counter.serialize(&ts);
        let loaded = counter.deserialize(&stored).unwrap();
        assert_eq!(loaded, ts);
    }

    #[test]
    fn test_tampered_payload_rejected() {
        let counter = SignedCounter::new([0x42; 32]);
        let stored = counter.serialize(&[1000.0, 2000.0]);
        let tampered = stored.replacen("1000", "9999", 1);
        assert!(counter.deserialize(&tampered).is_none());
    }

    #[test]
    fn test_fake_hmac_rejected() {
        let counter = SignedCounter::new([0x42; 32]);
        let fake = "1000.0,2000.0|deadbeef";
        assert!(counter.deserialize(fake).is_none());
    }

    #[test]
    fn test_malformed_no_pipe_rejected() {
        let counter = SignedCounter::new([0x42; 32]);
        assert!(counter.deserialize("no_pipe_separator").is_none());
    }

    #[test]
    fn test_nan_timestamps_filtered() {
        let counter = SignedCounter::new([0x42; 32]);
        // If somehow NaN got serialized, it should be filtered on load
        let stored = counter.serialize(&[1000.0]);
        let loaded = counter.deserialize(&stored).unwrap();
        for t in &loaded {
            assert!(!t.is_nan());
            assert!(!t.is_infinite());
            assert!(*t > 0.0);
        }
    }
}
```

The HMAC key should be derived from a device-specific secret (hardware ID, Keychain, etc.) so it's not trivially extractable. The `filter` on deserialization catches NaN/Infinity/negative values that could corrupt window calculations.

The key insight: Rust's `std::process::Command` does NOT invoke a shell. Arguments passed via `.arg()` are sent directly to the OS `exec` syscall as individual argv elements. Shell metacharacters (`$()`, backticks, `&&`, pipes) are treated as literal characters.

This is safe by construction, unlike Python's `subprocess.Popen(shell=True)` or C's `system()`.

```rust
use std::process::Command;
use std::path::PathBuf;

// SAFE: Command::arg passes the path as a single argv element.
// Even "$(whoami)" or "; rm -rf /" are literal strings, not executed.
fn spawn_with_model_path(path: &Path) -> std::io::Result<std::process::Output> {
    Command::new("python3")
        .arg("server.py")
        .arg("--model")
        .arg(path)  // Entire path is ONE argument, no shell expansion
        .output()
}

// UNSAFE: This invokes a shell. NEVER do this with untrusted input.
fn spawn_unsafe(path: &str) -> std::io::Result<std::process::Output> {
    Command::new("bash")
        .arg("-c")
        .arg(format!("python3 server.py --model {}", path))  // INJECTION!
        .output()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_p0_shell_metacharacters_safe_with_arg() {
        // This path contains shell injection characters
        let dangerous = PathBuf::from("/tmp/models/; rm -rf /; echo pwned");
        // Command::arg sends it as literal argv -- no shell interprets it
        let cmd = Command::new("echo")
            .arg(dangerous.to_str().unwrap())
            .output()
            .unwrap();
        let output = String::from_utf8_lossy(&cmd.stdout);
        // The entire string appears as output, proving no shell execution
        assert!(output.contains("; rm -rf /"));
    }

    #[test]
    fn test_p0_backtick_injection_literal() {
        let path = PathBuf::from("/tmp/$(whoami)");
        let cmd = Command::new("echo")
            .arg(path.to_str().unwrap())
            .output()
            .unwrap();
        let output = String::from_utf8_lossy(&cmd.stdout);
        // $(whoami) appears literally, not expanded
        assert!(output.contains("$(whoami)"));
    }

    #[test]
    fn test_p0_null_byte_in_path_fails_spawn() {
        // Null bytes cause exec to fail at OS level
        let path = "/tmp/model\0malicious";
        let result = std::ffi::CString::new(path);
        assert!(result.is_err(), "CString rejects interior null bytes");
    }
}
```

Rules: (1) never use `bash -c` with string formatting on untrusted input, (2) always use `.arg()` to pass individual arguments, (3) for piping code to a subprocess, use stdin (`Stdio::piped()`) rather than constructing shell commands. The subprocess receives its arguments via the kernel's argv mechanism, bypassing any shell interpretation entirely.

Permission enum forgery is a P0 auth bypass vector. The attack scenario: if permissions are represented as strings internally and an attacker can inject `"superadmin"` or `"root"`, they bypass permission checks. Using a Rust enum prevents this at the type level, but you should still test the boundaries.

```rust
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum Permission {
    FileRead,
    FileWrite,
    BashExecute,
    NetworkAccess,
}

impl Permission {
    pub fn from_str(s: &str) -> Option<Self> {
        match s {
            "file_read" => Some(Self::FileRead),
            "file_write" => Some(Self::FileWrite),
            "bash_execute" => Some(Self::BashExecute),
            "network_access" => Some(Self::NetworkAccess),
            _ => None,  // Reject unknown permissions
        }
    }

    pub fn all() -> &'static [Permission] {
        &[
            Permission::FileRead,
            Permission::FileWrite,
            Permission::BashExecute,
            Permission::NetworkAccess,
        ]
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_p0_arbitrary_permission_rejected() {
        assert!(Permission::from_str("superadmin").is_none());
        assert!(Permission::from_str("root").is_none());
        assert!(Permission::from_str("").is_none());
        assert!(Permission::from_str("file_read; DROP TABLE").is_none());
    }

    #[test]
    fn test_p0_null_byte_in_permission_rejected() {
        assert!(Permission::from_str("file_read\0").is_none());
        assert!(Permission::from_str("\0file_read").is_none());
    }

    #[test]
    fn test_valid_permissions_accepted() {
        assert_eq!(Permission::from_str("file_read"), Some(Permission::FileRead));
        assert_eq!(Permission::from_str("bash_execute"), Some(Permission::BashExecute));
    }

    #[test]
    fn test_all_cases_exact_count() {
        // If someone adds a permission, this test forces them to update the list
        assert_eq!(Permission::all().len(), 4,
            "Permission count changed -- update tests");
    }

    #[test]
    fn test_no_null_bytes_in_any_variant() {
        for perm in Permission::all() {
            let name = format!("{:?}", perm);
            assert!(!name.contains('\0'), "Permission {:?} contains null byte", perm);
        }
    }
}
```

The count test is particularly important: it acts as a canary. When a developer adds a new permission variant, the test fails and forces them to also add tests for it. This prevents untested permissions from slipping into production.

Unicode boundary issues are a P2 denial-of-service vulnerability. The attack scenario: a function slices a string at a byte offset that falls in the middle of a multi-byte UTF-8 character, causing a panic. In Rust, string slicing panics on invalid char boundaries.

Example: the function checks the last 80 bytes of a string:
```rust
// DANGEROUS: panics if byte (len-80) is mid-character
let tail = &text[text.len() - 80..];
```

For CJK text where each character is 3 bytes, byte offset 80 from the end almost certainly lands mid-character.

Fix: use `char_indices()` to find safe boundaries:

```rust
/// Get the last N characters (not bytes) of a string, safely.
fn safe_tail(s: &str, char_count: usize) -> &str {
    let char_start = s.chars().count().saturating_sub(char_count);
    s.char_indices()
        .nth(char_start)
        .map(|(byte_idx, _)| &s[byte_idx..])
        .unwrap_or(s)
}

/// Alternative: find the nearest char boundary at or after a byte offset.
fn safe_byte_tail(s: &str, max_bytes: usize) -> &str {
    if s.len() <= max_bytes {
        return s;
    }
    let target = s.len() - max_bytes;
    // Walk forward to find a valid char boundary
    let start = (target..s.len())
        .find(|&i| s.is_char_boundary(i))
        .unwrap_or(s.len());
    &s[start..]
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_p2_cjk_boundary_no_panic() {
        // Each CJK char is 3 bytes. 30 chars = 90 bytes.
        let cjk = "\u{4e00}".repeat(30);
        let tail = safe_tail(&cjk, 10);
        assert_eq!(tail.chars().count(), 10);
    }

    #[test]
    fn test_p2_byte_tail_cjk_no_panic() {
        let cjk = "\u{4e00}".repeat(30);
        let tail = safe_byte_tail(&cjk, 80);
        // Should not panic, and result should be valid UTF-8
        assert!(tail.len() <= 80 + 2); // might overshoot by up to 2 bytes for alignment
    }

    #[test]
    fn test_p2_emoji_boundary() {
        let emoji = "\u{1F600}".repeat(25); // 4 bytes each = 100 bytes
        let tail = safe_byte_tail(&emoji, 80);
        assert!(!tail.is_empty());
    }

    #[test]
    fn test_short_string_returns_full() {
        let short = "hello";
        assert_eq!(safe_tail(short, 100), "hello");
        assert_eq!(safe_byte_tail(short, 100), "hello");
    }
}
```

Rule: never use `&s[byte_offset..]` unless you've verified `s.is_char_boundary(byte_offset)`. Prefer `chars()` or `char_indices()` for character-level operations. In security-sensitive code, a panic is a denial of service.

Recovery parsing is inherently dangerous because it operates on freeform text from the model, not structured output. The attack scenario: the model intentionally outputs malformed text containing a hidden JSON tool call like `{"name": "bash", "arguments": {"command": "cat /etc/shadow"}}`. A permissive recovery parser extracts this and executes it.

The defense is an explicit tool name allowlist with a fail-safe empty default:

```rust
pub struct RecoveryPipeline {
    known_tools: Vec<String>,
}

impl RecoveryPipeline {
    /// Default: empty allowlist. Rejects ALL extracted tool calls.
    pub fn new() -> Self {
        Self { known_tools: vec![] }
    }

    /// Explicit allowlist. Only these tool names can be extracted.
    pub fn with_known_tools(tools: &[&str]) -> Self {
        Self {
            known_tools: tools.iter().map(|s| s.to_string()).collect(),
        }
    }

    pub fn attempt_extract(&self, text: &str) -> Option<ParsedToolCall> {
        // Try to find JSON object in the text
        let json_re = regex::Regex::new(r"\{[^}]+\}").unwrap();
        for mat in json_re.find_iter(text) {
            if let Ok(val) = serde_json::from_str::<serde_json::Value>(mat.as_str()) {
                if let Some(name) = val.get("name").and_then(|n| n.as_str()) {
                    // SECURITY: Only extract if name is in allowlist
                    if self.known_tools.contains(&name.to_string()) {
                        // Extract and return
                        return Some(parse_json_tool_call(&val));
                    }
                }
            }
        }
        None
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_p0_empty_allowlist_rejects_all() {
        let pipeline = RecoveryPipeline::new();
        let malicious = "Oops. {\"name\": \"bash\", \"arguments\": {\"command\": \"cat /etc/shadow\"}}";
        assert!(
            pipeline.attempt_extract(malicious).is_none(),
            "Empty allowlist must reject all extracted tool calls"
        );
    }

    #[test]
    fn test_p0_allowlist_rejects_unknown_tools() {
        let pipeline = RecoveryPipeline::with_known_tools(&["bash", "file_read"]);
        let input = "Use evil_tool: {\"name\": \"evil_tool\", \"arguments\": {}}";
        assert!(pipeline.attempt_extract(input).is_none());
    }

    #[test]
    fn test_allowlist_accepts_known_tools() {
        let pipeline = RecoveryPipeline::with_known_tools(&["bash", "file_read"]);
        let input = "Let me try: {\"name\": \"bash\", \"arguments\": {\"command\": \"ls\"}}";
        let result = pipeline.attempt_extract(input);
        assert!(result.is_some());
        assert_eq!(result.unwrap().name, "bash");
    }
}
```

The fail-safe default (empty allowlist = reject everything) means if a developer forgets to configure the allowlist, no tool calls are extracted. This is the secure-by-default principle: the system is safe in its unconfigured state.

Terminal escape sequence injection is a P1 vulnerability. The attack scenario: a compromised or malicious subprocess returns error messages containing ANSI escape codes like `\x1b[31mMALICIOUS\x1b[0m` or worse, sequences that rewrite terminal content, move the cursor, or change terminal settings.

In a TUI application, raw ANSI sequences can:
1. Overwrite displayed content to hide malicious actions
2. Change terminal colors to make warnings invisible
3. Use cursor repositioning to fake UI elements
4. On some terminals, execute arbitrary commands via title-setting sequences

```rust
/// Strip ANSI escape sequences from untrusted text before display.
pub fn strip_ansi(input: &str) -> String {
    let ansi_re = regex::Regex::new(
        r"\x1b\[[0-9;]*[a-zA-Z]|\x1b\][^\x07]*\x07|\x1b[()][AB012]"
    ).unwrap();
    let stripped = ansi_re.replace_all(input, "");

    // Also strip other control characters except newline and tab
    stripped.chars()
        .filter(|c| !c.is_control() || *c == '\n' || *c == '\t')
        .collect()
}

/// Process subprocess error for safe display in TUI.
pub fn safe_error_display(raw_error: &str) -> String {
    let stripped = strip_ansi(raw_error);
    // Truncate long errors
    if stripped.len() > 500 {
        format!("{}... [truncated]", &stripped[..500])
    } else {
        stripped
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_ansi_color_stripped() {
        let input = "\x1b[31mERROR\x1b[0m: file not found";
        let result = strip_ansi(input);
        assert_eq!(result, "ERROR: file not found");
        assert!(!result.contains('\x1b'));
    }

    #[test]
    fn test_cursor_movement_stripped() {
        let input = "\x1b[2J\x1b[HFake clean screen";
        let result = strip_ansi(input);
        assert_eq!(result, "Fake clean screen");
    }

    #[test]
    fn test_title_injection_stripped() {
        let input = "\x1b]0;EVIL TITLE\x07Normal text";
        let result = strip_ansi(input);
        assert_eq!(result, "Normal text");
    }

    #[test]
    fn test_normal_text_preserved() {
        let input = "error: file not found at /path/to/file";
        assert_eq!(strip_ansi(input), input);
    }
}
```

Also suppress subprocess stderr entirely when not needed:

```rust
// Route stderr to /dev/null to prevent injection
Command::new("python3")
    .arg("server.py")
    .stderr(std::process::Stdio::null())  // Suppress stderr
    .spawn()?;
```

Two layers: (1) suppress stderr when you don't need it, (2) strip ANSI sequences from any subprocess output before displaying it.

