The cooldown prevents a denial-of-service-by-annoyance attack where the model repeatedly requests the same permission the user already declined. The security concern: the cooldown state itself must not be bypassable.

```rust
use std::collections::HashSet;
use std::sync::Mutex;

pub struct PermissionManager {
    declined_this_session: Mutex<HashSet<Permission>>,
}

impl PermissionManager {
    pub fn new() -> Self {
        Self {
            declined_this_session: Mutex::new(HashSet::new()),
        }
    }

    pub fn is_declined_this_session(&self, perm: Permission) -> bool {
        self.declined_this_session.lock().unwrap().contains(&perm)
    }

    pub fn mark_declined(&self, perm: Permission) {
        self.declined_this_session.lock().unwrap().insert(perm);
    }

    pub async fn request(&self, perm: Permission) -> PermissionStatus {
        // Check cooldown FIRST
        if self.is_declined_this_session(perm) {
            return PermissionStatus::Denied;
        }

        // Check current OS-level status
        let current = self.check(perm);
        if current == PermissionStatus::Granted {
            return PermissionStatus::Granted;
        }

        // Request from OS/user
        let result = self.request_from_os(perm).await;
        if result != PermissionStatus::Granted {
            self.mark_declined(perm);
        }
        result
    }

    /// Only available in test builds. No public API to bypass cooldown.
    #[cfg(test)]
    pub fn reset_for_testing(&self) {
        self.declined_this_session.lock().unwrap().clear();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_cooldown_tracks_declined() {
        let mgr = PermissionManager::new();
        assert!(!mgr.is_declined_this_session(Permission::FileRead));
        mgr.mark_declined(Permission::FileRead);
        assert!(mgr.is_declined_this_session(Permission::FileRead));
        assert!(!mgr.is_declined_this_session(Permission::FileWrite));
    }

    #[test]
    fn test_cooldown_no_public_reset() {
        // The reset method is #[cfg(test)] only.
        // In production, there is NO way to clear the cooldown within a session.
        // This is by design: the model cannot bypass user refusal.
        let mgr = PermissionManager::new();
        mgr.mark_declined(Permission::Accessibility);
        assert!(mgr.is_declined_this_session(Permission::Accessibility));
        mgr.reset_for_testing();
        assert!(!mgr.is_declined_this_session(Permission::Accessibility));
    }

    #[tokio::test]
    async fn test_concurrent_checks_safe() {
        let mgr = std::sync::Arc::new(PermissionManager::new());
        let mut handles = vec![];
        for perm in [Permission::FileRead, Permission::FileWrite, Permission::BashExecute] {
            let m = mgr.clone();
            handles.push(tokio::spawn(async move {
                m.check(perm)
            }));
        }
        for h in handles {
            let _ = h.await.unwrap();
        }
        // No panic = no data race
    }
}
```

Critical: the `reset_for_testing()` method is gated behind `#[cfg(test)]`. In production builds, it doesn't exist. There is no public API to clear the declined set within a session. The model cannot bypass a user's refusal.
